				console.error('SSE Error:', error);

				// Try to parse error from last message
				try {
					const lastEvent = eventSource.lastEventId;
					// Error might be in the data
				} catch (e) {
					// Ignore
				}

				updateStatus('Connection error', 'error');
				eventSource.close();
				streamBtn.disabled = false;
			};
